<?php $pageTitle='Deposit Approvals'; include __DIR__ . '/../includes/admin_header.php'; if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $id=(int)$_POST['id']; banking_review_deposit($id, (string)$_POST['status'], (string)($_POST['review_note'] ?? ''), banking_actor('admin', (int)$admin['id'])); log_admin($admin['id'],'deposit_review','Reviewed deposit through service layer '.$id,null,null,['status'=>$_POST['status'],'note'=>$_POST['review_note'] ?? '']); flash('success','Deposit reviewed.'); header('Location: deposits.php'); exit; } $rows=db()->query('SELECT d.*, u.first_name,u.last_name,u.email FROM deposits d JOIN users u ON u.id=d.user_id ORDER BY d.created_at DESC'); ?>
